sys_script_include.script:
var TRACENowLogger = Class.create();

TRACENowLogger.prototype = {

    initialize: function(jobSysId, context) {
        this.jobSysId = jobSysId || '';
        this.context  = context  || 'TRACENow';
        this.buffer   = [];
    },

    info:  function(msg) { this._log('info',    msg); },
    warn:  function(msg) { this._log('warning', msg); },
    error: function(msg) { this._log('error',   msg); },

    _log: function(level, msg) {
        var entry = '[' + level.toUpperCase() + '][' + this.context + '] ' + msg;
        this.buffer.push(entry);
        gs.log(entry, 'TRACENow');

        // Persist per-record log when job context is available
        if (this.jobSysId) {
            try {
                var log = new GlideRecordSecure('x_sysus_tracenow_tracenow_migration_record_log');
                log.initialize();
                log.u_job     = this.jobSysId;
                log.u_status  = level;
                log.u_message = msg;
                log.u_created_on = new GlideDateTime().getValue();
                log.insert();
            } catch(e) {
                gs.log('TRACENowLogger persist error: ' + e.message, 'TRACENow');
            }
        }
    },

    flushToJob: function() {
        if (!this.jobSysId || this.buffer.length === 0) return;
        var job = new GlideRecordSecure('x_sysus_tracenow_tracenow_migration_record_log');
        if (job.get(this.jobSysId)) {
            job.u_run_log = this.buffer.join('\n');
            job.update();
        }
    },

    type: 'TRACENowLogger'
};
